def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0 or item > capacity:
            continue
        ratio = item / capacity
        score = 0
        exponential_sum = 0
        for x in range(1, 20):
            multiplier = 1 + (np.sin(x * ratio * np.pi) / (x + 1))
            exponential_sum += multiplier * (ratio ** x) / (x ** 1.5)
        score += exponential_sum * np.exp(-ratio)
        remaining = capacity - item
        if remaining <= 0:
            score = 0
        elif remaining < 0.02 * capacity:
            score *= 3.0
        elif remaining < 0.05 * capacity:
            score *= 2.0
        elif remaining < 0.15 * capacity:
            score *= 1.25
        else:
            score *= 0.6
        prime_factors = [2,3,5,7,11,13]
        factor_penalty = 0
        for pf in prime_factors:
            if int(capacity) % pf == 0 and int(item) % pf == 0:
                factor_penalty += 0.02 * pf
            elif int(capacity) % pf == 0 or int(item) % pf == 0:
                factor_penalty += 0.01 * pf
            else:
                factor_penalty -= 0.005 * pf
        score -= factor_penalty
        penalty = 0
        multipliers = [0.3, 0.2, 0.1, 0.05, 0.025]
        for k in range(1, 7):
            target = item * k
            diff = abs(capacity - target)
            tolerance = 0.02 * capacity * k
            if diff < tolerance:
                penalty += multipliers[min(k-1, 4)] * k
            elif diff < 1.5 * tolerance:
                penalty += multipliers[min(k-1, 4)] * 0.6 * k
            elif diff < 3 * tolerance:
                penalty -= multipliers[min(k-1, 4)] * 0.4 * k
            else:
                penalty -= multipliers[min(k-1, 4)] * 0.8 * k
        score += penalty
        if score < 0:
            score = 0
        if score > 2.0:
            for m in range(1, 5):
                avg = capacity / m
                deviation = abs(avg - item)
                threshold = 0.015 * avg
                if deviation < threshold:
                    increase = 0.1 * m
                    for n in range(m):
                        increase += (0.02 * n)
                    score *= (1 + increase)
                elif deviation < 3 * threshold:
                    score *= 0.9
                else:
                    score *= 0.85
        for iteration in range(3):
            adjustment = 0
            for p in range(1, 4):
                distance = abs((capacity / p) - item)
                limit = 0.01 * (capacity / p)
                if distance < limit:
                    adjustment += 0.05 * p
                else:
                    adjustment -= 0.03 * p
            score += adjustment * (0.9 ** iteration)
            if score < 0:
                score = 0
        priorities[i] = score
    return priorities
